case class Product(id: Int, name: String, description: String, price: Double)

class ProductsController @Inject()(cc: ControllerComponents)(implicit ec: DatabaseExecutor) extends AbstractController(cc) {
  
  val db = Database.forConfig("db")

  def searchProducts = Action.async { implicit request =>
    val sqlFragment = request.queryString.flatMap { case (key, values) => 
      if (key == "name" || key == "description") Some(s"${key} LIKE '%${values.head}%'") else None
